module RefModule(  
    input [71:0] matrix, // 3x3 matrix flattened (9x8 bits)  
    output reg [7:0] median  
);  
    integer i, j;  
    reg [7:0] unused_sorted [0:8];  

    always @(*) begin  
        // Unpacking the flattened input into an array  
        for (i = 0; i < 9; i = i + 1)  
            unused_sorted[i] = matrix[i*8 +: 8];  

        // Sorting the array using a simple bubble sort  
        for (i = 0; i < 9; i = i + 1)  
            for (j = 0; j < 8 - i; j = j + 1)  
                if (unused_sorted[j] > unused_sorted[j + 1]) begin  
                    // Swap  
                    unused_sorted[j] = unused_sorted[j] ^ unused_sorted[j + 1];  
                    unused_sorted[j + 1] = unused_sorted[j] ^ unused_sorted[j + 1];  
                    unused_sorted[j] = unused_sorted[j] ^ unused_sorted[j + 1];  
                end  

        // The median is the 5th element in the unused_sorted array  
        median = unused_sorted[4];  
    end  
endmodule
